     1→import { useState, useEffect, useCallback } from "react";
     2→import { useAuth } from "@workspace/replit-auth-web";
     3→
     4→// ── Types ────────────────────────────────────────────────────────────────────
     5→
     6→interface AdminUser {
     7→  id: string;
     8→  email: string | null;
     9→  firstName: string | null;
    10→  lastName: string | null;
