    41→const PLAN_META: Record<string, { label: string; accent: string; bg: string }> = {
    42→  free:       { label: "Free",       accent: "#6b7280", bg: "bg-silver/10" },
    43→  starter:    { label: "Starter",    accent: "#031E43", bg: "bg-cl-blue/10" },
    44→  pro:        { label: "Pro",        accent: "#2dd8a0", bg: "bg-cl-accent/10" },
    45→  business:   { label: "Business",  accent: "#f59e0b", bg: "bg-yellow-400/10" },
    46→  enterprise: { label: "Enterprise", accent: "#a855f7", bg: "bg-purple-400/10" },
    47→  none:       { label: "Sin plan",   accent: "#4b5563", bg: "bg-silver/10" },
    48→  trialing:   { label: "Prueba",     accent: "#f59e0b", bg: "bg-yellow-400/10" },
    49→};
    50→
    51→// ── Helpers ──────────────────────────────────────────────────────────────────
    52→
    53→function formatDate(d: string | null) {
    54→  if (!d) return "—";
    55→  const date = new Date(d);
    56→  if (date.getFullYear() > 2100) return "Sin vencimiento";
    57→  return date.toLocaleDateString("es-AR", { day: "numeric", month: "short", year: "numeric" });
    58→}
    59→
    60→function formatDateShort(d: string | null) {
    61→  if (!d) return "—";
    62→  return new Date(d).toLocaleDateString("es-AR", { day: "numeric", month: "short" });
    63→}
    64→
    65→// ── Shared sub-components ─────────────────────────────────────────────────────
    66→
    67→function PlanBadge({ plan, status }: { plan: string; status: string }) {
    68→  const key = status === "trialing" ? "trialing" : plan;
    69→  const m = PLAN_META[key] ?? PLAN_META.none;
    70→  return (
    71→    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[11px] font-bold ${m.bg}`}
    72→      style={{ color: m.accent }}>
    73→      {m.label}
    74→    </span>
    75→  );
    76→}
    77→
    78→function StatusDot({ status }: { status: string }) {
    79→  if (status === "active") return (
    80→    <span className="flex items-center gap-1.5 text-cl-accent text-xs font-semibold">
    81→      <span className="w-1.5 h-1.5 rounded-full bg-cl-accent animate-pulse inline-block" />Activo
    82→    </span>
    83→  );
    84→  if (status === "trialing") return (
    85→    <span className="flex items-center gap-1.5 text-yellow-400 text-xs font-semibold">
    86→      <span className="w-1.5 h-1.5 rounded-full bg-yellow-400 animate-pulse inline-block" />Prueba
    87→    </span>
    88→  );
    89→  return <span className="text-cool-steel/55 text-xs">{status === "none" ? "Sin suscripción" : status}</span>;
    90→}
    91→
    92→// token: verde >8h · amarillo 1-8h · rojo ≤0h / null
    93→function TokenBadge({ horas }: { horas: number | null }) {
    94→  if (horas === null) return <span className="text-cool-steel/40 text-xs">Sin token</span>;
    95→  if (horas <= 0)  return <span className="flex items-center gap-1 text-red-400 text-xs font-semibold"><span className="w-1.5 h-1.5 rounded-full bg-red-400 inline-block" />Expirado</span>;
    96→  if (horas <= 8)  return <span className="flex items-center gap-1 text-yellow-400 text-xs font-semibold"><span className="w-1.5 h-1.5 rounded-full bg-yellow-400 animate-pulse inline-block" />{horas}h</span>;
    97→  return <span className="flex items-center gap-1 text-cl-accent text-xs font-semibold"><span className="w-1.5 h-1.5 rounded-full bg-cl-accent inline-block" />{horas}h</span>;
    98→}
    99→
   100→// cert: verde >60d · amarillo 8-60d · rojo ≤7d / null
   101→function CertBadge({ dias }: { dias: number | null }) {
   102→  if (dias === null) return <span className="text-cool-steel/40 text-xs">Sin cert</span>;
   103→  if (dias <= 0)   return <span className="flex items-center gap-1 text-red-400 text-xs font-semibold"><i className="ti ti-certificate-off text-sm" />Expirado</span>;
   104→  if (dias <= 7)   return <span className="flex items-center gap-1 text-red-400 text-xs font-semibold"><i className="ti ti-certificate text-sm" />{dias}d</span>;
   105→  if (dias <= 60)  return <span className="flex items-center gap-1 text-yellow-400 text-xs font-semibold"><i className="ti ti-certificate text-sm" />{dias}d</span>;
   106→  return <span className="flex items-center gap-1 text-cl-accent text-xs font-semibold"><i className="ti ti-certificate text-sm" />{dias}d</span>;
   107→}
   108→
   109→function EnvBadge({ env }: { env: string }) {
   110→  if (env === "produccion") return <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-cl-accent/10 text-cl-accent">Producción</span>;
   111→  return <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-yellow-400/10 text-yellow-400">Homologación</span>;
   112→}
   113→
   114→// ── Main component ────────────────────────────────────────────────────────────
   115→
   116→export default function AdminPage() {
   117→  const { user, isLoading } = useAuth();
   118→  const [users, setUsers]         = useState<AdminUser[]>([]);
   119→  const [total, setTotal]         = useState(0);
   120→  const [loadingUsers, setLoadingUsers] = useState(true);
   121→
   122→  const [afipRows, setAfipRows]   = useState<AdminAfipRow[]>([]);
   123→  const [loadingAfip, setLoadingAfip] = useState(false);
   124→  const [renewingId, setRenewingId]   = useState<string | null>(null);
   125→  const [renewingAll, setRenewingAll] = useState(false);
   126→  const [renewResult, setRenewResult] = useState<{ ok: number; error: number } | null>(null);
   127→
   128→  const [updatingId, setUpdatingId] = useState<string | null>(null);
   129→  const [tab, setTab]   = useState<"users" | "afip" | "system">("users");
   130→  const [search, setSearch] = useState("");
   131→  const [filterPlan, setFilterPlan] = useState("all");
   132→  const [afipSearch, setAfipSearch] = useState("");
   133→
   134→  const isAdmin = !isLoading && user?.email?.endsWith("@clientum.com.ar") && user.email !== "demo@clientum.com.ar";
   135→
   136→  // ── Load users ──────────────────────────────────────────────────────────────
   137→  const loadUsers = useCallback(() => {
   138→    setLoadingUsers(true);
   139→    fetch("/api/admin/users", { credentials: "include" })
   140→      .then(r => r.json())
   141→      .then((d: { users: AdminUser[]; total: number }) => {
   142→        setUsers(d.users ?? []);
   143→        setTotal(d.total ?? 0);
   144→        setLoadingUsers(false);
   145→      })
   146→      .catch(() => setLoadingUsers(false));
   147→  }, []);
   148→
   149→  // ── Load AFIP ───────────────────────────────────────────────────────────────
   150→  const loadAfip = useCallback(() => {
   151→    setLoadingAfip(true);
   152→    fetch("/api/admin/afip", { credentials: "include" })
   153→      .then(r => r.json())
   154→      .then((d: { configs: AdminAfipRow[] }) => {
   155→        setAfipRows(d.configs ?? []);
   156→        setLoadingAfip(false);
   157→      })
   158→      .catch(() => setLoadingAfip(false));
   159→  }, []);
   160→
   161→  useEffect(() => {
   162→    if (!isAdmin) return;
   163→    loadUsers();
   164→  }, [isAdmin, loadUsers]);
   165→
   166→  useEffect(() => {
   167→    if (!isAdmin || tab !== "afip") return;
   168→    loadAfip();
   169→  }, [isAdmin, tab, loadAfip]);
   170→
   171→  // ── Renovar token ────────────────────────────────────────────────────────────
   172→  const handleRenew = async (userId: string) => {
   173→    setRenewingId(userId);
   174→    try {
   175→      await fetch(`/api/admin/afip/${userId}/renovar-token`, { method: "POST", credentials: "include" });
   176→      loadAfip();
   177→    } finally {
   178→      setRenewingId(null);
   179→    }
   180→  };
   181→
   182→  const handleRenewAll = async () => {
   183→    setRenewingAll(true);
   184→    setRenewResult(null);
   185→    try {
   186→      const r = await fetch("/api/admin/afip/renovar-todos", { method: "POST", credentials: "include" });
   187→      const d = await r.json() as { ok: number; error: number };
   188→      setRenewResult({ ok: d.ok, error: d.error });
   189→      loadAfip();
   190→    } finally {
   191→      setRenewingAll(false);
   192→    }
   193→  };
   194→
   195→  // ── Change plan ──────────────────────────────────────────────────────────────
   196→  const handlePlanChange = async (userId: string, plan: string) => {
   197→    setUpdatingId(userId);
   198→    try {
   199→      await fetch(`/api/admin/users/${userId}/plan`, {
   200→        method: "PATCH",
   201→        headers: { "Content-Type": "application/json" },
   202→        credentials: "include",
   203→        body: JSON.stringify({ plan, status: "active" }),
   204→      });
   205→      setUsers(prev => prev.map(u => u.id === userId ? { ...u, plan, status: "active" } : u));
   206→    } finally {
   207→      setUpdatingId(null);
   208→    }
   209→  };
   210→
   211→  // ── Guard ────────────────────────────────────────────────────────────────────
   212→  if (isLoading) {
   213→    return (
   214→      <div className="flex-1 flex items-center justify-center">
   215→        <div className="w-10 h-10 border-4 border-cl-accent border-t-transparent rounded-full animate-spin" />
   216→      </div>
   217→    );
   218→  }
   219→
   220→  if (!isAdmin) {
   221→    return (
   222→      <div className="flex-1 flex flex-col items-center justify-center gap-4 p-8">
   223→        <div className="w-16 h-16 rounded-2xl bg-red-400/10 flex items-center justify-center">
   224→          <i className="ti ti-shield-lock text-3xl text-red-400" />
   225→        </div>
   226→        <div className="text-center">
   227→          <h2 className="text-white font-bold text-lg">Acceso restringido</h2>
   228→          <p className="text-cool-steel text-sm mt-1">Esta sección es solo para administradores de Clientum.</p>
   229→        </div>
   230→      </div>
   231→    );
   232→  }
   233→
   234→  // ── Filtered lists ────────────────────────────────────────────────────────────
   235→  const filteredUsers = users.filter(u => {
   236→    const q = search.toLowerCase();
   237→    const matchSearch = !q
   238→      || (u.email ?? "").toLowerCase().includes(q)
   239→      || (u.firstName ?? "").toLowerCase().includes(q)
   240→      || (u.lastName ?? "").toLowerCase().includes(q);
   241→    const matchPlan = filterPlan === "all"
   242→      || (filterPlan === "trialing" ? u.status === "trialing" : u.plan === filterPlan);
   243→    return matchSearch && matchPlan;
   244→  });
   245→
   246→  const filteredAfip = afipRows.filter(r => {
   247→    const q = afipSearch.toLowerCase();
   248→    return !q
   249→      || (r.email ?? "").toLowerCase().includes(q)
   250→      || (r.cuit ?? "").includes(q)
   251→      || (r.razonSocial ?? "").toLowerCase().includes(q);
   252→  });
   253→
   254→  // ── Stats ─────────────────────────────────────────────────────────────────────
   255→  const userStats = [
   256→    { label: "Total usuarios",   value: total,                                                                                         icon: "ti-users",     accent: "#031E43" },
   257→    { label: "Enterprise / Biz", value: users.filter(u => u.plan === "enterprise" || u.plan === "business").length,                    icon: "ti-crown",     accent: "#a855f7" },
   258→    { label: "Pro",              value: users.filter(u => u.plan === "pro").length,                                                    icon: "ti-star",      accent: "#2dd8a0" },
   259→    { label: "En prueba",        value: users.filter(u => u.status === "trialing").length,                                             icon: "ti-clock",     accent: "#f59e0b" },
   260→    { label: "Starter",          value: users.filter(u => u.plan === "starter").length,                                                icon: "ti-bolt",      accent: "#3b82f6" },
   261→    { label: "Free / Sin plan",  value: users.filter(u => !u.plan || u.plan === "free" || u.plan === "none").length,                   icon: "ti-lock-open", accent: "#6b7280" },
   262→  ];
   263→
   264→  const afipTokenOk      = afipRows.filter(r => r.tokenHorasRestantes !== null && r.tokenHorasRestantes > 8).length;
   265→  const afipTokenWarn    = afipRows.filter(r => r.tokenHorasRestantes !== null && r.tokenHorasRestantes > 0 && r.tokenHorasRestantes <= 8).length;
   266→  const afipTokenExp     = afipRows.filter(r => r.tokenHorasRestantes !== null && r.tokenHorasRestantes <= 0).length;
   267→  const afipCertExp30    = afipRows.filter(r => r.certDiasRestantes !== null && r.certDiasRestantes <= 30 && r.certDiasRestantes > 0).length;
   268→  const afipCertExpired  = afipRows.filter(r => r.certDiasRestantes !== null && r.certDiasRestantes <= 0).length;
   269→  const afipTotalComp    = afipRows.reduce((sum, r) => sum + r.totalComprobantes, 0);
   270→
   271→  const TABS = [
   272→    { id: "users",  label: "Usuarios",     icon: "ti-users" },
   273→    { id: "afip",   label: "AFIP",         icon: "ti-building-bank" },
   274→    { id: "system", label: "Sistema",      icon: "ti-server" },
   275→  ] as const;
   276→
   277→  return (
   278→    <div className="p-6 max-w-7xl mx-auto space-y-6">
   279→
   280→      {/* Header */}
   281→      <div className="flex items-center justify-between">
   282→        <div className="flex items-center gap-3">
   283→          <div className="w-10 h-10 rounded-xl bg-purple-400/10 flex items-center justify-center">
   284→            <i className="ti ti-shield-lock text-xl text-purple-400" />
   285→          </div>
   286→          <div>
   287→            <h2 className="text-white font-bold text-lg">Panel de Administración</h2>
   288→            <p className="text-cool-steel text-xs">Solo visible para cuentas @clientum.com.ar</p>
   289→          </div>
   290→        </div>
   291→        <button
   292→          onClick={() => { loadUsers(); if (tab === "afip") loadAfip(); }}
   293→          disabled={loadingUsers || loadingAfip}
   294→          className="flex items-center gap-2 px-4 py-2 bg-navy-2 border border-silver/20 rounded-lg text-xs font-semibold text-cool-steel hover:text-white hover:border-silver/35 transition-all disabled:opacity-50">
   295→          <i className={`ti ti-refresh text-sm ${(loadingUsers || loadingAfip) ? "animate-spin" : ""}`} />
   296→          Actualizar
   297→        </button>
   298→      </div>
   299→
   300→      {/* Stats row — shown on users tab */}
   301→      {tab === "users" && (
   302→        <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-3">
   303→          {userStats.map(s => (
   304→            <div key={s.label} className="bg-navy-2 border border-silver/20 rounded-xl p-4">
   305→              <div className="w-8 h-8 rounded-lg flex items-center justify-center mb-2" style={{ background: `${s.accent}20` }}>
   306→                <i className={`ti ${s.icon} text-base`} style={{ color: s.accent }} />
   307→              </div>
   308→              <div className="text-2xl font-extrabold text-white">{loadingUsers ? "—" : s.value}</div>
   309→              <div className="text-cool-steel text-[11px] mt-0.5 leading-tight">{s.label}</div>
   310→            </div>
   311→          ))}
   312→        </div>
   313→      )}
   314→
   315→      {/* Stats row — shown on afip tab */}
   316→      {tab === "afip" && (
   317→        <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-3">
   318→          {[
   319→            { label: "Configs AFIP",     value: afipRows.length,  icon: "ti-building-bank", accent: "#031E43" },
   320→            { label: "Tokens activos",   value: afipTokenOk,      icon: "ti-check",         accent: "#2dd8a0" },
   321→            { label: "Tokens < 8h",      value: afipTokenWarn,    icon: "ti-clock",         accent: "#f59e0b" },
   322→            { label: "Tokens expirados", value: afipTokenExp,     icon: "ti-x",             accent: "#f87171" },
   323→            { label: "Certs por vencer", value: afipCertExp30,    icon: "ti-certificate",   accent: "#f59e0b" },
   324→            { label: "Total facturas",   value: afipTotalComp,    icon: "ti-receipt",       accent: "#a855f7" },
   325→          ].map(s => (
   326→            <div key={s.label} className="bg-navy-2 border border-silver/20 rounded-xl p-4">
   327→              <div className="w-8 h-8 rounded-lg flex items-center justify-center mb-2" style={{ background: `${s.accent}20` }}>
   328→                <i className={`ti ${s.icon} text-base`} style={{ color: s.accent }} />
   329→              </div>
   330→              <div className="text-2xl font-extrabold text-white">{loadingAfip ? "—" : s.value}</div>
   331→              <div className="text-cool-steel text-[11px] mt-0.5 leading-tight">{s.label}</div>
   332→            </div>
   333→          ))}
   334→        </div>
   335→      )}
   336→
   337→      {/* Tabs */}
   338→      <div className="flex gap-1 bg-navy-2 border border-silver/20 rounded-xl p-1 w-fit">
   339→        {TABS.map(t => (
   340→          <button key={t.id} onClick={() => setTab(t.id)}
   341→            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold transition-all ${
   342→              tab === t.id ? "bg-cl-accent/10 text-cl-accent" : "text-cool-steel hover:text-white"
   343→            }`}>
   344→            <i className={`ti ${t.icon} text-sm`} /> {t.label}
   345→          </button>
   346→        ))}
   347→      </div>
   348→
   349→      {/* ── Tab: Usuarios ─────────────────────────────────────────────────── */}
   350→      {tab === "users" && (
   351→        <div className="bg-navy-2 border border-silver/20 rounded-xl overflow-hidden">
   352→          <div className="p-4 border-b border-silver/15 flex flex-col sm:flex-row gap-3">
   353→            <div className="relative flex-1">
   354→              <i className="ti ti-search absolute left-3 top-1/2 -translate-y-1/2 text-cool-steel/55 text-sm" />
   355→              <input type="text" placeholder="Buscar por email o nombre..."
   356→                value={search} onChange={e => setSearch(e.target.value)}
   357→                className="w-full bg-navy border border-silver/20 rounded-lg pl-9 pr-4 py-2.5 text-sm text-white placeholder:text-cool-steel/45 focus:outline-none focus:border-cl-accent/50 transition-colors" />
   358→            </div>
   359→            <select value={filterPlan} onChange={e => setFilterPlan(e.target.value)}
   360→              className="bg-navy border border-silver/20 rounded-lg px-3 py-2.5 text-sm text-white focus:outline-none focus:border-cl-accent/50 transition-colors">
   361→              <option value="all">Todos los planes</option>
   362→              <option value="enterprise">Enterprise</option>
   363→              <option value="business">Business</option>
   364→              <option value="pro">Pro</option>
   365→              <option value="starter">Starter</option>
   366→              <option value="free">Free</option>
   367→              <option value="none">Sin plan</option>
   368→              <option value="trialing">⏳ En prueba</option>
   369→            </select>
   370→          </div>
   371→
   372→          {loadingUsers ? (
   373→            <div className="p-12 flex flex-col items-center gap-3">
   374→              <div className="w-8 h-8 border-2 border-cl-accent border-t-transparent rounded-full animate-spin" />
   375→              <p className="text-cool-steel text-sm">Cargando usuarios...</p>
   376→            </div>
   377→          ) : filteredUsers.length === 0 ? (
   378→            <div className="p-12 text-center">
   379→              <i className="ti ti-search-off text-3xl text-cool-steel/40 block mb-2" />
   380→              <p className="text-cool-steel text-sm">No se encontraron usuarios.</p>
   381→            </div>
   382→          ) : (
   383→            <div className="overflow-x-auto">
   384→              <table className="w-full text-sm">
   385→                <thead>
   386→                  <tr className="border-b border-silver/15">
   387→                    {["Usuario", "Plan", "Estado", "Vencimiento", "Registro", "MP Payment ID", "Cambiar plan"].map(h => (
   388→                      <th key={h} className="px-5 py-3 text-left text-[10px] font-bold uppercase tracking-widest text-cool-steel/45">{h}</th>
   389→                    ))}
   390→                  </tr>
